const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const server = http.createServer(app);

app.use(helmet());
app.use(express.json({ limit: '1kb' }));

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

const io = new Server(server, {
  cors: {
    origin: process.env.ALLOWED_ORIGIN || false,
    methods: ['GET', 'POST'],
    credentials: true,
  },
  pingTimeout: 10000,
  pingInterval: 5000,
  maxHttpBufferSize: 1e4,
});

// In-memory stores (use a proper database in production)
const users = new Map();
const sessions = new Map();
const activePlayers = new Map();
const leaderboard = [];
const gameStates = new Map();

const SALT_ROUNDS = 12;
const SESSION_TTL_MS = 30 * 60 * 1000;
const MAX_USERNAME_LENGTH = 20;
const MIN_USERNAME_LENGTH = 3;
const MAX_PASSWORD_LENGTH = 128;
const MIN_PASSWORD_LENGTH = 8;
const MAX_LEADERBOARD_SIZE = 100;
const MAX_SCORE = 1_000_000;
const SCORE_INCREMENT_MAX = 100;
const MOVE_COOLDOWN_MS = 50;

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function generateHmacSecret() {
  return crypto.randomBytes(64).toString('hex');
}

const SERVER_HMAC_SECRET = process.env.HMAC_SECRET || generateHmacSecret();

function computeScoreHmac(playerId, score, nonce) {
  return crypto
    .createHmac('sha256', SERVER_HMAC_SECRET)
    .update(`${playerId}:${score}:${nonce}`)
    .digest('hex');
}

function validateUsername(username) {
  if (typeof username !== 'string') return false;
  if (username.length < MIN_USERNAME_LENGTH || username.length > MAX_USERNAME_LENGTH) return false;
  return /^[a-zA-Z0-9_-]+$/.test(username);
}

function validatePassword(password) {
  if (typeof password !== 'string') return false;
  if (password.length < MIN_PASSWORD_LENGTH || password.length > MAX_PASSWORD_LENGTH) return false;
  return true;
}

function sanitizeString(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/[<>&"'/]/g, '');
}

function validateScore(score) {
  if (typeof score !== 'number') return false;
  if (!Number.isFinite(score)) return false;
  if (score < 0 || score > MAX_SCORE) return false;
  if (!Number.isInteger(score)) return false;
  return true;
}

function validateMove(move) {
  const allowedMoves = ['up', 'down', 'left', 'right', 'action'];
  if (!move || typeof move !== 'object') return false;
  if (typeof move.type !== 'string') return false;
  if (!allowedMoves.includes(move.type)) return false;
  if (move.timestamp !== undefined) {
    if (typeof move.timestamp !== 'number' || !Number.isFinite(move.timestamp)) return false;
  }
  return true;
}

function cleanExpiredSessions() {
  const now = Date.now();
  for (const [token, session] of sessions.entries()) {
    if (now - session.createdAt > SESSION_TTL_MS) {
      sessions.delete(token);
    }
  }
}

setInterval(cleanExpiredSessions, 60 * 1000);

function getSessionByToken(token) {
  if (typeof token !== 'string' || token.length !== 64) return null;
  const session = sessions.get(token);
  if (!session) return null;
  if (Date.now() - session.createdAt > SESSION_TTL_MS) {
    sessions.delete(token);
    return null;
  }
  return session;
}

// --- Server-side game state management ---
class ServerGameState {
  constructor(playerId) {
    this.playerId = playerId;
    this.score = 0;
    this.position = { x: 0, y: 0 };
    this.lastMoveTime = 0;
    this.moveCount = 0;
    this.startTime = Date.now();
    this.collectibles = this.generateCollectibles();
    this.collectedItems = new Set();
  }

  generateCollectibles() {
    const items = [];
    const rng = crypto.randomInt;
    for (let i = 0; i < 50; i++) {
      items.push({
        id: i,
        x: rng(0, 1000),
        y: rng(0, 1000),
        value: rng(1, 11),
      });
    }
    return items;
  }

  applyMove(move) {
    const now = Date.now();
    if (now - this.lastMoveTime < MOVE_COOLDOWN_MS) {
      return { valid: false, reason: 'move_too_fast' };
    }

    const step = 10;
    const prevPosition = { ...this.position };

    switch (move.type) {
      case 'up':
        this.position.y = Math.max(0, this.position.y - step);
        break;
      case 'down':
        this.position.y = Math.min(1000, this.position.y + step);
        break;
      case 'left':
        this.position.x = Math.max(0, this.position.x - step);
        break;
      case 'right':
        this.position.x = Math.min(1000, this.position.x + step);
        break;
      case 'action':
        return this.tryCollect();
      default:
        return { valid: false, reason: 'invalid_move_type' };
    }

    this.lastMoveTime = now;
    this.moveCount++;

    return {
      valid: true,
      position: { ...this.position },
      score: this.score,
    };
  }

  tryCollect() {
    const collectRadius = 20;
    let collected = false;

    for (const item of this.collectibles) {
      if (this.collectedItems.has(item.id)) continue;

      const dx = this.position.x - item.x;
      const dy = this.position.y - item.y;
      const distance = Math.sqrt(dx * dx + dy * dy);

      if (distance <= collectRadius) {
        this.collectedItems.add(item.id);
        const scoreIncrement = item.value;

        if (scoreIncrement > 0 && scoreIncrement <= SCORE_INCREMENT_MAX) {
          this.score += scoreIncrement;
          if (this.score > MAX_SCORE) this.score = MAX_SCORE;
          collected = true;
          break;
        }
      }
    }

    this.lastMoveTime = Date.now();

    return {
      valid: true,
      collected,
      position: { ...this.position },
      score: this.score,
    };
  }

  getAuthoritative() {
    return {
      score: this.score,
      position: { ...this.position },
      collectiblesRemaining: this.collectibles.length - this.collectedItems.size,
    };
  }
}

// --- HTTP endpoints for registration and login ---
app.post('/api/register', async (req, res) => {
  try {
    const { username, password } = req.body;

    if (!validateUsername(username)) {
      return res.status(400).json({
        error: 'Invalid username. Must be 3-20 alphanumeric characters, hyphens, or underscores.',
      });
    }

    if (!validatePassword(password)) {
      return res.status(400).json({
        error: 'Invalid password. Must be 8-128 characters.',
      });
    }

    if (users.has(username)) {
      // Use generic message to avoid user enumeration
      return res.status(409).json({ error: 'Registration failed.' });
    }

    const hashedPassword = await bcrypt.hash(password, SALT_ROUNDS);
    users.set(username, {
      username,
      hashedPassword,
      createdAt: Date.now(),
      highScore: 0,
    });

    console.log(`User registered: ${sanitizeString(username)}`);
    return res.status(201).json({ message: 'Registration successful.' });
  } catch (err) {
    console.error('Registration error');
    return res.status(500).json({ error: 'Internal server error.' });
  }
});

app.post('/api/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    if (!validateUsername(username) || !validatePassword(password)) {
      return res.status(401).json({ error: 'Invalid credentials.' });
    }

    const user = users.get(username);
    if (!user) {
      // Perform dummy bcrypt compare to prevent timing attacks
      await bcrypt.hash('dummy', SALT_ROUNDS);
      return res.status(401).json({ error: 'Invalid credentials.' });
    }

    const passwordMatch = await bcrypt.compare(password, user.hashedPassword);
    if (!passwordMatch) {
      return res.status(401).json({ error: 'Invalid credentials.' });
    }

    // Invalidate any existing session for this user
    for (const [token, session] of sessions.entries()) {
      if (session.username === username) {
        sessions.delete(token);
      }
    }

    const sessionToken = generateSessionToken();
    sessions.set(sessionToken, {
      username,
      createdAt: Date.now(),
      ip: req.ip,
    });

    console.log(`User logged in: ${sanitizeString(username)}`);
    return res.status(200).json({ sessionToken });
  } catch (err) {
    console.error('Login error');
    return res.status(500).json({ error: 'Internal server error.' });
  }
});

