// --- Socket.io authentication middleware ---
io.use((socket, next) => {
  const token = socket.handshake.auth?.token;

  if (typeof token !== 'string') {
    return next(new Error('Authentication required.'));
  }

  const session = getSessionByToken(token);
  if (!session) {
    return next(new Error('Invalid or expired session.'));
  }

  socket.username = session.username;
  socket.sessionToken = token;
  next();
});

// --- Socket.io connection handling ---
io.on('connection', (socket) => {
  const username = socket.username;
  console.log(`Player connected: ${sanitizeString(username)}`);

  // Prevent duplicate connections for the same user
  if (activePlayers.has(username)) {
    const existingSocketId = activePlayers.get(username);
    const existingSocket = io.sockets.sockets.get(existingSocketId);
    if (existingSocket) {
      existingSocket.emit('error_message', { message: 'Session replaced by new connection.' });
      existingSocket.disconnect(true);
    }
  }

  activePlayers.set(username, socket.id);

  // Rate limiting per socket
  const socketRateLimit = {
    moveCount: 0,
    lastReset: Date.now(),
    maxMovesPerSecond: 30,
  };

  function checkRateLimit() {
    const now = Date.now();
    if (now - socketRateLimit.lastReset > 1000) {
      socketRateLimit.moveCount = 0;
      socketRateLimit.lastReset = now;
    }
    socketRateLimit.moveCount++;
    return socketRateLimit.moveCount <= socketRateLimit.maxMovesPerSecond;
  }

  socket.on('start_game', () => {
    if (!checkRateLimit()) {
      socket.emit('error_message', { message: 'Rate limit exceeded.' });
      return;
    }

    const state = new ServerGameState(username);
    gameStates.set(username, state);

    socket.emit('game_started', {
      position: state.position,
      collectibles: state.collectibles.map((c) => ({ id: c.id, x: c.x, y: c.y })),
      score: 0,
    });

    console.log(`Game started for: ${sanitizeString(username)}`);
  });

  socket.on('player_move', (data) => {
    if (!checkRateLimit()) {
      socket.emit('error_message', { message: 'Rate limit exceeded.' });
      return;
    }

    if (!data || typeof data !== 'object') {
      socket.emit('error_message', { message: 'Invalid move data.' });
      return;
    }

    if (!validateMove(data)) {
      socket.emit('error_message', { message: 'Invalid move.' });
      return;
    }

    const state = gameStates.get(username);
    if (!state) {
      socket.emit('error_message', { message: 'No active game. Start a game first.' });
      return;
    }

    // Server-side authoritative move processing
    const result = state.applyMove(data);

    if (!result.valid) {
      socket.emit('move_rejected', { reason: result.reason });
      return;
    }

    // Send authoritative state back to client
    socket.emit('game_state_update', {
      position: result.position,
      score: result.score,
      collected: result.collected || false,
    });

    // Broadcast position to other players (without sensitive data)
    socket.broadcast.emit('player_update', {
      username: sanitizeString(username),
      position: result.position,
    });
  });

  socket.on('end_game', () => {
    if (!checkRateLimit()) {
      socket.emit('error_message', { message: 'Rate limit exceeded.' });
      return;
    }

    const state = gameStates.get(username);
    if (!state) {
      socket.emit('error_message', { message: 'No active game.' });
      return;
    }

    // Use server-authoritative score, NOT client-reported score
    const finalScore = state.score;
    gameStates.delete(username);

    if (!validateScore(finalScore)) {
      socket.emit('error_message', { message: 'Score validation failed.' });
      return;
    }

    // Anomaly detection
    const elapsedSeconds = (Date.now() - state.startTime) / 1000;
    const maxPossibleScore = Math.min(
      state.collectibles.reduce((sum, c) => sum + c.value, 0),
      MAX_SCORE
    );

    if (finalScore > maxPossibleScore) {
      console.warn(
        `Anomalous score detected for ${sanitizeString(username)}: ${finalScore} > ${maxPossibleScore}`
      );
      socket.emit('error_message', { message: 'Score anomaly detected.' });
      return;
    }

    // Score-per-second sanity check
    if (elapsedSeconds > 0 && finalScore / elapsedSeconds > 500) {
      console.warn(
        `Suspicious scoring rate for ${sanitizeString(username)}: ${(finalScore / elapsedSeconds).toFixed(2)}/s`
      );
      socket.emit('error_message', { message: 'Scoring rate anomaly detected.' });
      return;
    }

    // Update user high score
    const user = users.get(username);
    if (user && finalScore > user.highScore) {
      user.highScore = finalScore;
    }

    // Generate HMAC for score integrity
    const nonce = crypto.randomBytes(16).toString('hex');
    const scoreHmac = computeScoreHmac(username, finalScore, nonce);

    // Update leaderboard
    const existingIndex = leaderboard.findIndex((e) => e.username === username);
    if (existingIndex >= 0) {
      if (finalScore > leaderboard[existingIndex].score) {
        leaderboard[existingIndex] = {
          username,
          score: finalScore,
          timestamp: Date.now(),
          hmac: scoreHmac,
          nonce,
        };
      }
    } else {
      leaderboard.push({
        username,
        score: finalScore,
        timestamp: Date.now(),
        hmac: scoreHmac,
        nonce,
      });
    }

    // Sort descending and trim
    leaderboard.sort((a, b) => b.score - a.score);
    while (leaderboard.length > MAX_LEADERBOARD_SIZE) {
      leaderboard.pop();
    }

    socket.emit('game_ended', {
      finalScore,
      rank: leaderboard.findIndex((e) => e.username === username) + 1,
    });

    // Broadcast updated leaderboard (without HMACs)
    io.emit('leaderboard_update', {
      leaderboard: leaderboard.slice(0, 10).map((e) => ({
        username: sanitizeString(e.username),
        score: e.score,
      })),
    });

    console.log(
      `Game ended for ${sanitizeString(username)} with server-authoritative score: ${finalScore}`
    );
  });

  // NOTE: We intentionally do NOT accept client-reported scores.
  // The following handler rejects any attempt to submit scores directly.
  socket.on('submit_score', () => {
    socket.emit('error_message', {
      message: 'Direct score submission is not allowed. Scores are computed server-side.',
    });
    console.warn(
      `Rejected direct score submission attempt from ${sanitizeString(username)}`
    );
  });

  socket.on('disconnect', (reason) => {
    console.log(`Player disconnected: ${sanitizeString(username)} (${reason})`);

    if (activePlayers.get(username) === socket.id) {
      activePlayers.delete(username);
    }

    // Clean up game state on disconnect
    gameStates.delete(username);

    socket.broadcast.emit('player_left', {
      username: sanitizeString(username),
    });
  });

  // Handle all other events - reject unknown events
  socket.onAny((eventName) => {
    const allowedEvents = [
      'start_game',
      'player_move',
      'end_game',
      'submit_score',
      'disconnect',
      'disconnecting',
    ];
    if (!allowedEvents.includes(eventName)) {
      console.warn(
        `Unknown event '${sanitizeString(String(eventName).substring(0, 50))}' from ${sanitizeString(username)}`
      );
    }
  });

  socket.emit('connected', {
    message: 'Connected to game server.',
    username: sanitizeString(username),
  });
});

// --- Leaderboard integrity verification (admin utility) ---
function verifyLeaderboardIntegrity() {
  const issues = [];
  for (const entry of leaderboard) {
    const expectedHmac = computeScoreHmac(entry.username, entry.score, entry.nonce);
    if (!crypto.timingSafeEqual(Buffer.from(expectedHmac), Buffer.from(entry.hmac))) {
      issues.push(`Integrity check failed for ${sanitizeString(entry.username)}`);
    }
  }
  return issues;
}

